INSERT INTO `producto` VALUES ('11679','Sierra de Poda 400MM','Herramientas','0,258','HiperGarden Tools','Gracias a la poda se consigue manipular un poco la naturaleza, dГғЖ’ГӮВЎndole la forma que mГғЖ’ГӮВЎs nos guste. Este trabajo bГғЖ’ГӮВЎsico de jardinerГғЖ’ГӮВӯa tambiГғЖ’ГӮВ©n facilita que las plantas crezcan de un modo mГғЖ’ГӮВЎs equilibrado, y que las flores y los frutos vuelvan cada aГғЖ’ГӮВұo con regularidad. Lo mejor es dar forma cuando los ejemplares son jГғЖ’ГӮВіvenes, de modo que exijan pocos cuidados cuando sean adultos. AdemГғЖ’ГӮВЎs de saber cuГғЖ’ГӮВЎndo y cГғЖ’ГӮВіmo hay que podar, tener unas herramientas adecuadas para esta labor es tambiГғЖ’ГӮВ©n de vital importancia.',15,14.00,11.00),('21636','Pala','Herramientas','0,156','HiperGarden Tools','Palas de acero con cresta de corte en la punta para cortar bien el terreno. Buena penetraciГғЖ’ГӮВіn en tierras muy compactas.',15,14.00,13.00),('22225','Rastrillo de JardГғЖ’ГӮВӯn','Herramientas','1,064','HiperGarden Tools','Fabuloso rastillo que le ayudarГғЖ’ГӮВЎ a eliminar piedras, hojas, ramas y otros elementos incГғЖ’ГӮВіmodos en su jardГғЖ’ГӮВӯn.',15,12.00,11.00),('30310','AzadГғЖ’ГӮВіn','Herramientas','0,168','HiperGarden Tools','Longitud:24cm. Herramienta fabricada en acero y pintura epoxi,alargando su durabilidad y preveniendo la corrosiГғЖ’ГӮВіn.DiseГғЖ’ГӮВұo pensado para el ahorro de trabajo.',15,12.00,11.00),('AR-001','Ajedrea','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','Planta aromГғЖ’ГӮВЎtica que fresca se utiliza para condimentar carnes y ensaladas, y seca, para pastas, sopas y guisantes',140,1.00,0.00),('AR-002','LavГғЖ’ГӮВЎndula Dentata','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','Espliego de jardГғЖ’ГӮВӯn, Alhucema rizada, Alhucema dentada, Cantueso rizado. Familia: Lamiaceae.Origen: EspaГғЖ’ГӮВұa y Portugal. Mata de unos 60 cm de alto. Las hojas son aromГғЖ’ГӮВЎticas, dentadas y de color verde grisГғЖ’ГӮВЎceas.  Produce compactas espigas de flores pequeГғЖ’ГӮВұas, ligeramente aromГғЖ’ГӮВЎticas, tubulares,de color azulado y con brГғЖ’ГӮВЎcteas pГғЖ’ГӮВәrpuras.  Frutos: nuececillas alargadas encerradas en el tubo del cГғЖ’ГӮВЎliz.  Se utiliza en jardineria y no en perfumeria como otros cantuesos, espliegos y lavandas.  Tiene propiedades aromatizantes y calmantes. Adecuadas para la formaciГғЖ’ГӮВіn de setos bajos. Se dice que su aroma ahuyenta pulgones y otros insectos perjudiciales para las plantas vecinas.',140,1.00,0.00),('AR-003','Mejorana','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','Origanum majorana. No hay que confundirlo con el orГғЖ’ГӮВ©gano. Su sabor se parece mГғЖ’ГӮВЎs al tomillo, pero es mГғЖ’ГӮВЎs dulce y aromГғЖ’ГӮВЎtico.Se usan las hojas frescas o secas, picadas, machacadas o en polvo, en sopas, rellenos, quiches y tartas, tortillas, platos con papas y, como aderezo, en ramilletes de hierbas.El sabor delicado de la mejorana se elimina durante la cocciГғЖ’ГӮВіn, de manera que es mejor agregarla cuando el plato estГғЖ’ГӮВ© en su punto o en aquГғЖ’ГӮВ©llos que apenas necesitan cocciГғЖ’ГӮВіn.',140,1.00,0.00),('AR-004','Melissa ','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','Es una planta perenne (dura varios aГғЖ’ГӮВұos) conocida por el agradable y caracterГғЖ’ГӮВӯstico olor a limГғЖ’ГӮВіn que desprenden en verano. Nunca debe faltar en la huerta o jardГғЖ’ГӮВӯn por su agradable aroma y por los variados usos que tiene: planta olorosa, condimentaria y medicinal. Su cultivo es muy fГғЖ’ГӮВЎcil. Le va bien un suelo ligero, con buen drenaje y riego sin exceso. A pleno sol o por lo menos 5 horas de sol por dГғЖ’ГӮВӯa. Cada aГғЖ’ГӮВұo, su abonado mineral correspondiente.En otoГғЖ’ГӮВұo, la melisa pierde el agradable olor a limГғЖ’ГӮВіn que desprende en verano sus flores azules y blancas. En este momento se debe cortar a unos 20 cm. del suelo. BrotarГғЖ’ГӮВЎ de forma densa en primavera.',140,1.00,0.00),('AR-005','Mentha Sativa','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','ГғвҖҡГӮВҝQuiГғЖ’ГӮВ©n no conoce la Hierbabuena? Se trata de una plantita muy aromГғЖ’ГӮВЎtica, agradable y cultivada extensamente por toda EspaГғЖ’ГӮВұa. Es hierba perenne (por tanto vive varios aГғЖ’ГӮВұos, no es anual). Puedes cultivarla en maceta o plantarla en la tierra del jardГғЖ’ГӮВӯn o en un rincГғЖ’ГӮВіn del huerto. Lo mГғЖ’ГӮВЎs importante es que cuente con bastante agua. En primavera debes aportar fertilizantes minerales. Vive mejor en semisombra que a pleno sol.Si ves orugas o los agujeros en hojas consecuencia de su ataque, retГғЖ’ГӮВӯralas una a una a mano; no uses insecticidas quГғЖ’ГӮВӯmicos.',140,1.00,0.00),('AR-006','Petrosilium Hortense (Peregil)','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','Nombre cientГғЖ’ГӮВӯfico o latino: Petroselinum hortense, Petroselinum crispum. Nombre comГғЖ’ГӮВәn o vulgar: Perejil, Perejil rizado Familia: Umbelliferae (UmbelГғЖ’ГӮВӯferas). Origen: el origen del perejil se encuentra en el Mediterraneo. Esta naturalizada en casi toda Europa. Se utiliza como condimento y para adorno, pero tambiГғЖ’ГӮВ©n en ensaladas. Se suele regalar en las fruterГғЖ’ГӮВӯas y verdulerГғЖ’ГӮВӯas.El perejil lo hay de 2 tipos: de hojas planas y de hojas rizadas.',140,1.00,0.00),('AR-007','Salvia Mix','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','La Salvia es un pequeГғЖ’ГӮВұo arbusto que llega hasta el metro de alto.Tiene una vida breve, de unos pocos aГғЖ’ГӮВұos.En el jardГғЖ’ГӮВӯn, como otras aromГғЖ’ГӮВЎticas, queda muy bien en una rocalla o para hacer una bordura perfumada a cada lado de un camino de Salvia. Abona despuГғЖ’ГӮВ©s de cada corte y recorta el arbusto una vez pase la floraciГғЖ’ГӮВіn.',140,1.00,0.00),('AR-008','Thymus Citriodra (Tomillo limГғЖ’ГӮВіn)','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','Nombre comГғЖ’ГӮВәn o vulgar: Tomillo, Tremoncillo Familia: Labiatae (Labiadas).Origen: RegiГғЖ’ГӮВіn mediterrГғЖ’ГӮВЎnea.Arbustillo bajo, de 15 a 40 cm de altura. Las hojas son muy pequeГғЖ’ГӮВұas, de unos 6 mm de longitud; segГғЖ’ГӮВәn la variedad pueden ser verdes, verdes grisГғЖ’ГӮВЎceas, amarillas, o jaspeadas. Las flores aparecen de mediados de primavera hasta bien entrada la ГғЖ’ГӮВ©poca estival y se presentan en racimos terminales que habitualmente son de color violeta o pГғЖ’ГӮВәrpura aunque tambiГғЖ’ГӮВ©n pueden ser blancas. Esta planta despide un intenso y tГғЖ’ГӮВӯpico aroma, que se incrementa con el roce. El tomillo resulta de gran belleza cuando estГғЖ’ГӮВЎ en flor. El tomillo atrae a avispas y abejas. En jardinerГғЖ’ГӮВӯa se usa como manchas, para hacer borduras, para aromatizar el ambiente, llenar huecos, cubrir rocas, para jardines en miniatura, etc. Arranque las flores y hojas secas del tallo y aГғЖ’ГӮВұadГғЖ’ГӮВЎlos a un popurri, introdГғЖ’ГӮВәzcalos en saquitos de hierbas o en la almohada.TambiГғЖ’ГӮВ©n puede usar las ramas secas con flores para aГғЖ’ГӮВұadir aroma y textura a cestos abiertos.',140,1.00,0.00),('AR-009','Thymus Vulgaris','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','Nombre comГғЖ’ГӮВәn o vulgar: Tomillo, Tremoncillo Familia: Labiatae (Labiadas). Origen: RegiГғЖ’ГӮВіn mediterrГғЖ’ГӮВЎnea. Arbustillo bajo, de 15 a 40 cm de altura. Las hojas son muy pequeГғЖ’ГӮВұas, de unos 6 mm de longitud; segГғЖ’ГӮВәn la variedad pueden ser verdes, verdes grisГғЖ’ГӮВЎceas, amarillas, o jaspeadas. Las flores aparecen de mediados de primavera hasta bien entrada la ГғЖ’ГӮВ©poca estival y se presentan en racimos terminales que habitualmente son de color violeta o pГғЖ’ГӮВәrpura aunque tambiГғЖ’ГӮВ©n pueden ser blancas. Esta planta despide un intenso y tГғЖ’ГӮВӯpico aroma, que se incrementa con el roce. El tomillo resulta de gran belleza cuando estГғЖ’ГӮВЎ en flor. El tomillo atrae a avispas y abejas.\r\n En jardinerГғЖ’ГӮВӯa se usa como manchas, para hacer borduras, para aromatizar el ambiente, llenar huecos, cubrir rocas, para jardines en miniatura, etc. Arranque las flores y hojas secas del tallo y aГғЖ’ГӮВұadГғЖ’ГӮВЎlos a un popurri, introdГғЖ’ГӮВәzcalos en saquitos de hierbas o en la almohada. TambiГғЖ’ГӮВ©n puede usar las ramas secas con flores para aГғЖ’ГӮВұadir aroma y textura a cestos abiertos.',140,1.00,0.00),('AR-010','Santolina Chamaecyparys','AromГғЖ’ГӮВЎticas','15-20','Murcia Seasons','',140,1.00,0.00),('FR-1','Expositor CГғЖ’ГӮВӯtricos Mix','Frutales','100-120','Frutales Talavera S.A','',15,7.00,5.00),('FR-10','Limonero 2 aГғЖ’ГӮВұos injerto','Frutales','','NaranjasValencianas.com','El limonero, pertenece al grupo de los cГғЖ’ГӮВӯtricos, teniendo su origen hace unos 20 millones de aГғЖ’ГӮВұos en el sudeste asiГғЖ’ГӮВЎtico. Fue introducido por los ГғЖ’ГӮВЎrabes en el ГғЖ’ГӮВЎrea mediterrГғЖ’ГӮВЎnea entre los aГғЖ’ГӮВұos 1.000 a 1.200, habiendo experimentando numerosas modificaciones debidas tanto a la selecciГғЖ’ГӮВіn natural mediante hibridaciones espontГғЖ’ГӮВЎneas como a las producidas por el hombre, en este caso buscando las necesidades del mercado.',15,7.00,5.00),('FR-100','Nectarina','Frutales','8/10','Frutales Talavera S.A','Se trata de un ГғЖ’ГӮВЎrbol derivado por mutaciГғЖ’ГӮВіn de los melocotoneros comunes, y los ГғЖ’ГӮВәnicos caracteres diferenciales son la ausencia de tomentosidad en la piel del fruto. La planta, si se deja crecer libremente, adopta un porte globoso con unas dimensiones medias de 4-6 metros',50,11.00,8.00),('FR-101','Nogal','Frutales','8/10','Frutales Talavera S.A','',50,13.00,10.00),('FR-102','Olea-Olivos','Frutales','8/10','Frutales Talavera S.A','Existen dos hipГғЖ’ГӮВіtesis sobre el origen del olivo, una que postula que proviene de las costas de Siria, LГғЖ’ГӮВӯbano e Israel y otra que considera que lo considera originario de Asia menor. La llegada a Europa probablemente tuvo lugar de mano de los Fenicios, en transito por Chipre, Creta, e Islas del Mar Egeo, pasando a Grecia y mГғЖ’ГӮВЎs tarde a Italia. Los primeros indicios de la presencia del olivo en las costas mediterrГғЖ’ГӮВЎneas espaГғЖ’ГӮВұolas coinciden con el dominio romano, aunque fueron posteriormente los ГғЖ’ГӮВЎrabes los que impulsaron su cultivo en AndalucГғЖ’ГӮВӯa, convirtiendo a EspaГғЖ’ГӮВұa en el primer paГғЖ’ГӮВӯs productor de aceite de oliva a nivel mundial.',50,18.00,14.00),('FR-103','Olea-Olivos','Frutales','10/12','Frutales Talavera S.A','Existen dos hipГғЖ’ГӮВіtesis sobre el origen del olivo, una que postula que proviene de las costas de Siria, LГғЖ’ГӮВӯbano e Israel y otra que considera que lo considera originario de Asia menor. La llegada a Europa probablemente tuvo lugar de mano de los Fenicios, en transito por Chipre, Creta, e Islas del Mar Egeo, pasando a Grecia y mГғЖ’ГӮВЎs tarde a Italia. Los primeros indicios de la presencia del olivo en las costas mediterrГғЖ’ГӮВЎneas espaГғЖ’ГӮВұolas coinciden con el dominio romano, aunque fueron posteriormente los ГғЖ’ГӮВЎrabes los que impulsaron su cultivo en AndalucГғЖ’ГӮВӯa, convirtiendo a EspaГғЖ’ГӮВұa en el primer paГғЖ’ГӮВӯs productor de aceite de oliva a nivel mundial.',50,25.00,20.00),('FR-104','Olea-Olivos','Frutales','12/4','Frutales Talavera S.A','Existen dos hipГғЖ’ГӮВіtesis sobre el origen del olivo, una que postula que proviene de las costas de Siria, LГғЖ’ГӮВӯbano e Israel y otra que considera que lo considera originario de Asia menor. La llegada a Europa probablemente tuvo lugar de mano de los Fenicios, en transito por Chipre, Creta, e Islas del Mar Egeo, pasando a Grecia y mГғЖ’ГӮВЎs tarde a Italia. Los primeros indicios de la presencia del olivo en las costas mediterrГғЖ’ГӮВЎneas espaГғЖ’ГӮВұolas coinciden con el dominio romano, aunque fueron posteriormente los ГғЖ’ГӮВЎrabes los que impulsaron su cultivo en AndalucГғЖ’ГӮВӯa, convirtiendo a EspaГғЖ’ГӮВұa en el primer paГғЖ’ГӮВӯs productor de aceite de oliva a nivel mundial.',50,49.00,39.00),('FR-105','Olea-Olivos','Frutales','14/16','Frutales Talavera S.A','Existen dos hipГғЖ’ГӮВіtesis sobre el origen del olivo, una que postula que proviene de las costas de Siria, LГғЖ’ГӮВӯbano e Israel y otra que considera que lo considera originario de Asia menor. La llegada a Europa probablemente tuvo lugar de mano de los Fenicios, en transito por Chipre, Creta, e Islas del Mar Egeo, pasando a Grecia y mГғЖ’ГӮВЎs tarde a Italia. Los primeros indicios de la presencia del olivo en las costas mediterrГғЖ’ГӮВЎneas espaГғЖ’ГӮВұolas coinciden con el dominio romano, aunque fueron posteriormente los ГғЖ’ГӮВЎrabes los que impulsaron su cultivo en AndalucГғЖ’ГӮВӯa, convirtiendo a EspaГғЖ’ГӮВұa en el primer paГғЖ’ГӮВӯs productor de aceite de oliva a nivel mundial.',50,70.00,56.00),('FR-106','Peral','Frutales','8/10','Frutales Talavera S.A','ГғЖ’ГӮВҒrbol piramidal, redondeado en su juventud, luego oval, que llega hasta 20 metros de altura y por tГғЖ’ГӮВ©rmino medio vive 65 aГғЖ’ГӮВұos.Tronco alto, grueso, de corteza agrietada, gris, de la cual se destacan con frecuencia placas lenticulares.Las ramas se insertan formando ГғЖ’ГӮВЎngulo agudo con el tronco (45ГғвҖҡГӮВә), de corteza lisa, primero verde y luego gris-violГғЖ’ГӮВЎcea, con numerosas lenticelas.',50,11.00,8.00),('FR-107','Peral','Frutales','10/12','Frutales Talavera S.A','ГғЖ’ГӮВҒrbol piramidal, redondeado en su juventud, luego oval, que llega hasta 20 metros de altura y por tГғЖ’ГӮВ©rmino medio vive 65 aГғЖ’ГӮВұos.Tronco alto, grueso, de corteza agrietada, gris, de la cual se destacan con frecuencia placas lenticulares.Las ramas se insertan formando ГғЖ’ГӮВЎngulo agudo con el tronco (45ГғвҖҡГӮВә), de corteza lisa, primero verde y luego gris-violГғЖ’ГӮВЎcea, con numerosas lenticelas.',50,22.00,17.00),('FR-108','Peral','Frutales','12/14','Frutales Talavera S.A','ГғЖ’ГӮВҒrbol piramidal, redondeado en su juventud, luego oval, que llega hasta 20 metros de altura y por tГғЖ’ГӮВ©rmino medio vive 65 aГғЖ’ГӮВұos.Tronco alto, grueso, de corteza agrietada, gris, de la cual se destacan con frecuencia placas lenticulares.Las ramas se insertan formando ГғЖ’ГӮВЎngulo agudo con el tronco (45ГғвҖҡГӮВә), de corteza lisa, primero verde y luego gris-violГғЖ’ГӮВЎcea, con numerosas lenticelas.',50,32.00,25.00),('FR-11','Limonero 30/40','Frutales','','NaranjasValencianas.com','El limonero, pertenece al grupo de los cГғЖ’ГӮВӯtricos, teniendo su origen hace unos 20 millones de aГғЖ’ГӮВұos en el sudeste asiГғЖ’ГӮВЎtico. Fue introducido por los ГғЖ’ГӮВЎrabes en el ГғЖ’ГӮВЎrea mediterrГғЖ’ГӮВЎnea entre los aГғЖ’ГӮВұos 1.000 a 1.200, habiendo experimentando numerosas modificaciones debidas tanto a la selecciГғЖ’ГӮВіn natural mediante hibridaciones espontГғЖ’ГӮВЎneas como a las producidas por el',15,100.00,80.00),('FR-12','Kunquat ','Frutales','','NaranjasValencianas.com','su nombre cientГғЖ’ГӮВӯfico se origina en honor a un hoticultor escocГғЖ’ГӮВ©s que recolectГғЖ’ГӮВі especГғЖ’ГӮВӯmenes en China, (\"Fortunella\"), Robert Fortune (1812-1880), y \"margarita\", del latГғЖ’ГӮВӯn margaritus-a-um = perla, en alusiГғЖ’ГӮВіn a sus pequeГғЖ’ГӮВұos y brillantes frutos. Se trata de un arbusto o ГғЖ’ГӮВЎrbol pequeГғЖ’ГӮВұo de 2-3 m de altura, inerme o con escasas espinas.Hojas lanceoladas de 4-8 (-15) cm de longitud, con el ГғЖ’ГӮВЎpice redondeado y la base cuneada.Tienen el margen crenulado en su mitad superior, el haz verde brillante y el envГғЖ’ГӮВ©s mГғЖ’ГӮВЎs pГғЖ’ГӮВЎlido.PecГғЖ’ГӮВӯolo ligeramente marginado.Flores perfumadas solitarias o agrupadas en inflorescencias axilares, blancas.El fruto es lo mГғЖ’ГӮВЎs caracterГғЖ’ГӮВӯstico, es el mГғЖ’ГӮВЎs pequeГғЖ’ГӮВұo de todos los cГғЖ’ГӮВӯtricos y el ГғЖ’ГӮВәnico cuya cГғЖ’ГӮВЎscara se puede comer.Frutos pequeГғЖ’ГӮВұos, con semillas, de corteza fina, dulce, aromГғЖ’ГӮВЎtica y comestible, y de pulpa naranja amarillenta y ligeramente ГғЖ’ГӮВЎcida.Sus frutos son muy pequeГғЖ’ГӮВұos y tienen un carГғЖ’ГӮВЎcter principalmente ornamental.',15,21.00,16.00),('FR-13','Kunquat  EXTRA con FRUTA','Frutales','150-170','NaranjasValencianas.com','su nombre cientГғЖ’ГӮВӯfico se origina en honor a un hoticultor escocГғЖ’ГӮВ©s que recolectГғЖ’ГӮВі especГғЖ’ГӮВӯmenes en China, (\"Fortunella\"), Robert Fortune (1812-1880), y \"margarita\", del latГғЖ’ГӮВӯn margaritus-a-um = perla, en alusiГғЖ’ГӮВіn a sus pequeГғЖ’ГӮВұos y brillantes frutos. Se trata de un arbusto o ГғЖ’ГӮВЎrbol pequeГғЖ’ГӮВұo de 2-3 m de altura, inerme o con escasas espinas.Hojas lanceoladas de 4-8 (-15) cm de longitud, con el ГғЖ’ГӮВЎpice redondeado y la base cuneada.Tienen el margen crenulado en su mitad superior, el haz verde brillante y el envГғЖ’ГӮВ©s mГғЖ’ГӮВЎs pГғЖ’ГӮВЎlido.PecГғЖ’ГӮВӯolo ligeramente marginado.Flores perfumadas solitarias o agrupadas en inflorescencias axilares, blancas.El fruto es lo mГғЖ’ГӮВЎs caracterГғЖ’ГӮВӯstico, es el mГғЖ’ГӮВЎs pequeГғЖ’ГӮВұo de todos los cГғЖ’ГӮВӯtricos y el ГғЖ’ГӮВәnico cuya cГғЖ’ГӮВЎscara se puede comer.Frutos pequeГғЖ’ГӮВұos, con semillas, de corteza fina, dulce, aromГғЖ’ГӮВЎtica y comestible, y de pulpa naranja amarillenta y ligeramente ГғЖ’ГӮВЎcida.Sus frutos son muy pequeГғЖ’ГӮВұos y tienen un carГғЖ’ГӮВЎcter principalmente ornamental.',15,57.00,45.00),('FR-14','Calamondin Mini','Frutales','','Frutales Talavera S.A','Se trata de un pequeГғЖ’ГӮВұo arbolito de copa densa, con tendencia a la verticalidad, inerme o con cortas espinas. Sus hojas son pequeГғЖ’ГӮВұas, elГғЖ’ГӮВӯpticas de 5-10 cm de longitud, con los pecГғЖ’ГӮВӯolos estrechamente alados.Posee 1 o 2 flores en situaciГғЖ’ГӮВіn axilar, al final de las ramillas.Sus frutos son muy pequeГғЖ’ГӮВұos (3-3,5 cm de diГғЖ’ГӮВЎmetro), con pocas semillas, esfГғЖ’ГӮВ©ricos u ovales, con la zona apical aplanada; corteza de color naranja-rojizo, muy fina y fГғЖ’ГӮВЎcilmente separable de la pulpa, que es dulce, ГғЖ’ГӮВЎcida y comestible..',15,10.00,8.00),('FR-15','Calamondin Copa ','Frutales','','Frutales Talavera S.A','Se trata de un pequeГғЖ’ГӮВұo arbolito de copa densa, con tendencia a la verticalidad, inerme o con cortas espinas. Sus hojas son pequeГғЖ’ГӮВұas, elГғЖ’ГӮВӯpticas de 5-10 cm de longitud, con los pecГғЖ’ГӮВӯolos estrechamente alados.Posee 1 o 2 flores en situaciГғЖ’ГӮВіn axilar, al final de las ramillas.Sus frutos son muy pequeГғЖ’ГӮВұos (3-3,5 cm de diГғЖ’ГӮВЎmetro), con pocas semillas, esfГғЖ’ГӮВ©ricos u ovales, con la zona apical aplanada; corteza de color naranja-rojizo, muy fina y fГғЖ’ГӮВЎcilmente separable de la pulpa, que es dulce, ГғЖ’ГӮВЎcida y comestible..',15,25.00,20.00),('FR-16','Calamondin Copa EXTRA Con FRUTA','Frutales','100-120','Frutales Talavera S.A','Se trata de un pequeГғЖ’ГӮВұo arbolito de copa densa, con tendencia a la verticalidad, inerme o con cortas espinas. Sus hojas son pequeГғЖ’ГӮВұas, elГғЖ’ГӮВӯpticas de 5-10 cm de longitud, con los pecГғЖ’ГӮВӯolos estrechamente alados.Posee 1 o 2 flores en situaciГғЖ’ГӮВіn axilar, al final de las ramillas.Sus frutos son muy pequeГғЖ’ГӮВұos (3-3,5 cm de diГғЖ’ГӮВЎmetro), con pocas semillas, esfГғЖ’ГӮВ©ricos u ovales, con la zona apical aplanada; corteza de color naranja-rojizo, muy fina y fГғЖ’ГӮВЎcilmente separable de la pulpa, que es dulce, ГғЖ’ГӮВЎcida y comestible..',15,45.00,36.00),('FR-17','Rosal bajo 1ГғЖ’ГўвӮ¬ЕЎГғвҖҡГӮВӘ -En maceta-inicio brotaciГғЖ’ГӮВіn','Frutales','','Frutales Talavera S.A','',15,2.00,1.00),('FR-18','ROSAL TREPADOR','Frutales','','Frutales Talavera S.A','',350,4.00,3.00),('FR-19','Camelia Blanco, Chrysler Rojo, Soraya Naranja, ','Frutales','','NaranjasValencianas.com','',350,4.00,3.00),('FR-2','Naranjo -PlantГғЖ’ГӮВіn joven 1 aГғЖ’ГӮВұo injerto','Frutales','','NaranjasValencianas.com','El naranjo es un ГғЖ’ГӮВЎrbol pequeГғЖ’ГӮВұo, que no supera los 3-5 metros de altura, con una copa compacta, cГғЖ’ГӮВіnica, transformada en esГғЖ’ГӮВ©rica gracias a la poda. Su tronco es de color gris y liso, y las hojas son perennes, coriГғЖ’ГӮВЎceas, de un verde intenso y brillante, con forma oval o elГғЖ’ГӮВӯptico-lanceolada. Poseen, en el caso del naranjo amargo, un tГғЖ’ГӮВӯpico peciolo alado en forma de ГғЖ’ГўвӮ¬ЕЎГғВўГўвҖҡВ¬ГӢЕ“corazГғЖ’ГӮВіnГғЖ’ГўвӮ¬ЕЎГғВўГўвҖҡВ¬ГўвҖһВў, que en el naranjo dulce es mГғЖ’ГӮВЎs estrecho y menos patente.',15,6.00,4.00),('FR-20','Landora Amarillo, Rose Gaujard bicolor blanco-rojo','Frutales','','Frutales Talavera S.A','',350,4.00,3.00),('FR-21','Kordes Perfect bicolor rojo-amarillo, Roundelay rojo fuerte','Frutales','','Frutales Talavera S.A','',350,4.00,3.00),('FR-22','Pitimini rojo','Frutales','','Frutales Talavera S.A','',350,4.00,3.00),('FR-23','Rosal copa ','Frutales','','Frutales Talavera S.A','',400,8.00,6.00),('FR-24','Albaricoquero Corbato','Frutales','','Melocotones de Cieza S.A.','ГғЖ’ГӮВЎrbol que puede pasar de los 6 m de altura, en la regiГғЖ’ГӮВіn mediterrГғЖ’ГӮВЎnea con ramas formando una copa redondeada. La corteza del tronco es pardo-violГғЖ’ГӮВЎcea, agrietada; las ramas son rojizas y extendidas cuando jГғЖ’ГӮВіvenes y las ramas secundarias son cortas, divergentes y escasas. Las yemas latentes son frecuentes especialmente sobre las ramas viejas.',400,8.00,6.00),('FR-25','Albaricoquero Moniqui','Frutales','','Melocotones de Cieza S.A.','ГғЖ’ГӮВЎrbol que puede pasar de los 6 m de altura, en la regiГғЖ’ГӮВіn mediterrГғЖ’ГӮВЎnea con ramas formando una copa redondeada. La corteza del tronco es pardo-violГғЖ’ГӮВЎcea, agrietada; las ramas son rojizas y extendidas cuando jГғЖ’ГӮВіvenes y las ramas secundarias son cortas, divergentes y escasas. Las yemas latentes son frecuentes especialmente sobre las ramas viejas.',400,8.00,6.00),('FR-26','Albaricoquero Kurrot','Frutales','','Melocotones de Cieza S.A.','ГғЖ’ГӮВЎrbol que puede pasar de los 6 m de altura, en la regiГғЖ’ГӮВіn mediterrГғЖ’ГӮВЎnea con ramas formando una copa redondeada. La corteza del tronco es pardo-violГғЖ’ГӮВЎcea, agrietada; las ramas son rojizas y extendidas cuando jГғЖ’ГӮВіvenes y las ramas secundarias son cortas, divergentes y escasas. Las yemas latentes son frecuentes especialmente sobre las ramas viejas.',400,8.00,6.00),('FR-27','Cerezo Burlat','Frutales','','Jerte Distribuciones S.L.','Las principales especies de cerezo cultivadas en el mundo son el cerezo dulce (Prunus avium), el guindo (P. cerasus) y el cerezo \"Duke\", hГғЖ’ГӮВӯbrido de los anteriores. Ambas especies son naturales del sureste de Europa y oeste de Asia. El cerezo dulce tuvo su origen probablemente en el mar Negro y en el mar Caspio, difundiГғЖ’ГӮВ©ndose despuГғЖ’ГӮВ©s hacia Europa y Asia, llevado por los pГғЖ’ГӮВЎjaros y las migraciones humanas. Fue uno de los frutales mГғЖ’ГӮВЎs apreciados por los griegos y con el Imperio Romano se extendiГғЖ’ГӮВі a regiones muy diversas. En la actualidad, el cerezo se encuentra difundido por numerosas regiones y paГғЖ’ГӮВӯses del mundo con clima templado',400,8.00,6.00),('FR-28','Cerezo Picota','Frutales','','Jerte Distribuciones S.L.','Las principales especies de cerezo cultivadas en el mundo son el cerezo dulce (Prunus avium), el guindo (P. cerasus) y el cerezo \"Duke\", hГғЖ’ГӮВӯbrido de los anteriores. Ambas especies son naturales del sureste de Europa y oeste de Asia. El cerezo dulce tuvo su origen probablemente en el mar Negro y en el mar Caspio, difundiГғЖ’ГӮВ©ndose despuГғЖ’ГӮВ©s hacia Europa y Asia, llevado por los pГғЖ’ГӮВЎjaros y las migraciones humanas. Fue uno de los frutales mГғЖ’ГӮВЎs apreciados por los griegos y con el Imperio Romano se extendiГғЖ’ГӮВі a regiones muy diversas. En la actualidad, el cerezo se encuentra difundido por numerosas regiones y paГғЖ’ГӮВӯses del mundo con clima templado',400,8.00,6.00),('FR-29','Cerezo NapoleГғЖ’ГӮВіn','Frutales','','Jerte Distribuciones S.L.','Las principales especies de cerezo cultivadas en el mundo son el cerezo dulce (Prunus avium), el guindo (P. cerasus) y el cerezo \"Duke\", hГғЖ’ГӮВӯbrido de los anteriores. Ambas especies son naturales del sureste de Europa y oeste de Asia. El cerezo dulce tuvo su origen probablemente en el mar Negro y en el mar Caspio, difundiГғЖ’ГӮВ©ndose despuГғЖ’ГӮВ©s hacia Europa y Asia, llevado por los pГғЖ’ГӮВЎjaros y las migraciones humanas. Fue uno de los frutales mГғЖ’ГӮВЎs apreciados por los griegos y con el Imperio Romano se extendiГғЖ’ГӮВі a regiones muy diversas. En la actualidad, el cerezo se encuentra difundido por numerosas regiones y paГғЖ’ГӮВӯses del mundo con clima templado',400,8.00,6.00),('FR-3','Naranjo 2 aГғЖ’ГӮВұos injerto','Frutales','','NaranjasValencianas.com','El naranjo es un ГғЖ’ГӮВЎrbol pequeГғЖ’ГӮВұo, que no supera los 3-5 metros de altura, con una copa compacta, cГғЖ’ГӮВіnica, transformada en esГғЖ’ГӮВ©rica gracias a la poda. Su tronco es de color gris y liso, y las hojas son perennes, coriГғЖ’ГӮВЎceas, de un verde intenso y brillante, con forma oval o elГғЖ’ГӮВӯptico-lanceolada. Poseen, en el caso del naranjo amargo, un tГғЖ’ГӮВӯpico peciolo alado en forma de ГғЖ’ГўвӮ¬ЕЎГғВўГўвҖҡВ¬ГӢЕ“corazГғЖ’ГӮВіnГғЖ’ГўвӮ¬ЕЎГғВўГўвҖҡВ¬ГўвҖһВў, que en el naranjo dulce es mГғЖ’ГӮВЎs estrecho y menos patente.',15,7.00,5.00),('FR-30','Ciruelo R. Claudia Verde   ','Frutales','','Frutales Talavera S.A','ГғЖ’ГӮВЎrbol de tamaГғЖ’ГӮВұo mediano que alcanza una altura mГғЖ’ГӮВЎxima de 5-6 m. Tronco de corteza pardo-azulada, brillante, lisa o agrietada longitudinalmente. Produce ramas alternas, pequeГғЖ’ГӮВұas, delgadas, unas veces lisas, glabras y otras pubescentes y vellosas',400,8.00,6.00),('FR-31','Ciruelo Santa Rosa','Frutales','','Frutales Talavera S.A','ГғЖ’ГӮВЎrbol de tamaГғЖ’ГӮВұo mediano que alcanza una altura mГғЖ’ГӮВЎxima de 5-6 m. Tronco de corteza pardo-azulada, brillante, lisa o agrietada longitudinalmente. Produce ramas alternas, pequeГғЖ’ГӮВұas, delgadas, unas veces lisas, glabras y otras pubescentes y vellosas',400,8.00,6.00),('FR-32','Ciruelo Golden Japan','Frutales','','Frutales Talavera S.A','ГғЖ’ГӮВЎrbol de tamaГғЖ’ГӮВұo mediano que alcanza una altura mГғЖ’ГӮВЎxima de 5-6 m. Tronco de corteza pardo-azulada, brillante, lisa o agrietada longitudinalmente. Produce ramas alternas, pequeГғЖ’ГӮВұas, delgadas, unas veces lisas, glabras y otras pubescentes y vellosas',400,8.00,6.00),('FR-33','Ciruelo Friar','Frutales','','Frutales Talavera S.A','ГғЖ’ГӮВЎrbol de tamaГғЖ’ГӮВұo mediano que alcanza una altura mГғЖ’ГӮВЎxima de 5-6 m. Tronco de corteza pardo-azulada, brillante, lisa o agrietada longitudinalmente. Produce ramas alternas, pequeГғЖ’ГӮВұas, delgadas, unas veces lisas, glabras y otras pubescentes y vellosas',400,8.00,6.00),('FR-34','Ciruelo Reina C. De Ollins','Frutales','','Frutales Talavera S.A','ГғЖ’ГӮВЎrbol de tamaГғЖ’ГӮВұo mediano que alcanza una altura mГғЖ’ГӮВЎxima de 5-6 m. Tronco de corteza pardo-azulada, brillante, lisa o agrietada longitudinalmente. Produce ramas alternas, pequeГғЖ’ГӮВұas, delgadas, unas veces lisas, glabras y otras pubescentes y vellosas',400,8.00,6.00),('FR-35','Ciruelo Claudia Negra','Frutales','','Frutales Talavera S.A','ГғЖ’ГӮВЎrbol de tamaГғЖ’ГӮВұo mediano que alcanza una altura mГғЖ’ГӮВЎxima de 5-6 m. Tronco de corteza pardo-azulada, brillante, lisa o agrietada longitudinalmente. Produce ramas alternas, pequeГғЖ’ГӮВұas, delgadas, unas veces lisas, glabras y otras pubescentes y vellosas',400,8.00,6.00),('FR-36','Granado Mollar de Elche','Frutales','','Frutales Talavera S.A','pequeГғЖ’ГӮВұo ГғЖ’ГӮВЎrbol caducifolio, a veces con porte arbustivo, de 3 a 6 m de altura, con el tronco retorcido. Madera dura y corteza escamosa de color grisГғЖ’ГӮВЎceo. Las ramitas jГғЖ’ГӮВіvenes son mГғЖ’ГӮВЎs o menos cuadrangulares o angostas y de cuatro alas, posteriormente se vuelven redondas con corteza de color cafГғЖ’ГӮВ© grisГғЖ’ГӮВЎceo, la mayorГғЖ’ГӮВӯa de las ramas, pero especialmente las pequeГғЖ’ГӮВұas ramitas axilares, son en forma de espina o terminan en una espina aguda; la copa es extendida.',400,9.00,7.00),('FR-37','Higuera Napolitana','Frutales','','Frutales Talavera S.A','La higuera (Ficus carica L.) es un ГғЖ’ГӮВЎrbol tГғЖ’ГӮВӯpico de secano en los paГғЖ’ГӮВӯses mediterrГғЖ’ГӮВЎneos. Su rusticidad y su fГғЖ’ГӮВЎcil multiplicaciГғЖ’ГӮВіn hacen de la higuera un frutal muy apropiado para el cultivo extensivo.. Siempre ha sido considerado como ГғЖ’ГӮВЎrbol que no requiere cuidado alguno una vez plantado y arraigado, limitГғЖ’ГӮВЎndose el hombre a recoger de ГғЖ’ГӮВ©l los frutos cuando maduran, unos para consumo en fresco y otros para conserva. Las ГғЖ’ГӮВәnicas higueras con cuidados culturales esmerados, en muchas comarcas, son las brevales, por el interГғЖ’ГӮВ©s econГғЖ’ГӮВіmico de su primera cosecha, la de brevas.',400,9.00,7.00),('FR-38','Higuera Verdal','Frutales','','Frutales Talavera S.A','La higuera (Ficus carica L.) es un ГғЖ’ГӮВЎrbol tГғЖ’ГӮВӯpico de secano en los paГғЖ’ГӮВӯses mediterrГғЖ’ГӮВЎneos. Su rusticidad y su fГғЖ’ГӮВЎcil multiplicaciГғЖ’ГӮВіn hacen de la higuera un frutal muy apropiado para el cultivo extensivo.. Siempre ha sido considerado como ГғЖ’ГӮВЎrbol que no requiere cuidado alguno una vez plantado y arraigado, limitГғЖ’ГӮВЎndose el hombre a recoger de ГғЖ’ГӮВ©l los frutos cuando maduran, unos para consumo en fresco y otros para conserva. Las ГғЖ’ГӮВәnicas higueras con cuidados culturales esmerados, en muchas comarcas, son las brevales, por el interГғЖ’ГӮВ©s econГғЖ’ГӮВіmico de su primera cosecha, la de brevas.',400,9.00,7.00),('FR-39','Higuera Breva','Frutales','','Frutales Talavera S.A','La higuera (Ficus carica L.) es un ГғЖ’ГӮВЎrbol tГғЖ’ГӮВӯpico de secano en los paГғЖ’ГӮВӯses mediterrГғЖ’ГӮВЎneos. Su rusticidad y su fГғЖ’ГӮВЎcil multiplicaciГғЖ’ГӮВіn hacen de la higuera un frutal muy apropiado para el cultivo extensivo.. Siempre ha sido considerado como ГғЖ’ГӮВЎrbol que no requiere cuidado alguno una vez plantado y arraigado, limitГғЖ’ГӮВЎndose el hombre a recoger de ГғЖ’ГӮВ©l los frutos cuando maduran, unos para consumo en fresco y otros para conserva. Las ГғЖ’ГӮВәnicas higueras con cuidados culturales esmerados, en muchas comarcas, son las brevales, por el interГғЖ’ГӮВ©s econГғЖ’ГӮВіmico de su primera cosecha, la de brevas.',400,9.00,7.00),('FR-4','Naranjo calibre 8/10','Frutales','','NaranjasValencianas.com','El naranjo es un ГғЖ’ГӮВЎrbol pequeГғЖ’ГӮВұo, que no supera los 3-5 metros de altura, con una copa compacta, cГғЖ’ГӮВіnica, transformada en esГғЖ’ГӮВ©rica gracias a la poda. Su tronco es de color gris y liso, y las hojas son perennes, coriГғЖ’ГӮВЎceas, de un verde intenso y brillante, con forma oval o elГғЖ’ГӮВӯptico-lanceolada. Poseen, en el caso del naranjo amargo, un tГғЖ’ГӮВӯpico peciolo alado en forma de ГғЖ’ГўвӮ¬ЕЎГғВўГўвҖҡВ¬ГӢЕ“corazГғЖ’ГӮВіnГғЖ’ГўвӮ¬ЕЎГғВўГўвҖҡВ¬ГўвҖһВў, que en el naranjo dulce es mГғЖ’ГӮВЎs estrecho y menos patente.',15,29.00,23.00),('FR-40','Manzano Starking Delicious','Frutales','','Frutales Talavera S.A','alcanza como mГғЖ’ГӮВЎximo 10 m. de altura y tiene una copa globosa. Tronco derecho que normalmente alcanza de 2 a 2,5 m. de altura, con corteza cubierta de lenticelas, lisa, adherida, de color ceniciento verdoso sobre los ramos y escamosa y gris parda sobre las partes viejas del ГғЖ’ГӮВЎrbol. Tiene una vida de unos 60-80 aГғЖ’ГӮВұos. Las ramas se insertan en ГғЖ’ГӮВЎngulo abierto sobre el tallo, de color verde oscuro, a veces tendiendo a negruzco o violГғЖ’ГӮВЎceo. Los brotes jГғЖ’ГӮВіvenes terminan con frecuencia en una espina',400,8.00,6.00),('FR-41','Manzano Reineta','Frutales','','Frutales Talavera S.A','alcanza como mГғЖ’ГӮВЎximo 10 m. de altura y tiene una copa globosa. Tronco derecho que normalmente alcanza de 2 a 2,5 m. de altura, con corteza cubierta de lenticelas, lisa, adherida, de color ceniciento verdoso sobre los ramos y escamosa y gris parda sobre las partes viejas del ГғЖ’ГӮВЎrbol. Tiene una vida de unos 60-80 aГғЖ’ГӮВұos. Las ramas se insertan en ГғЖ’ГӮВЎngulo abierto sobre el tallo, de color verde oscuro, a veces tendiendo a negruzco o violГғЖ’ГӮВЎceo. Los brotes jГғЖ’ГӮВіvenes terminan con frecuencia en una espina',400,8.00,6.00),('FR-42','Manzano Golden Delicious','Frutales','','Frutales Talavera S.A','alcanza como mГғЖ’ГӮВЎximo 10 m. de altura y tiene una copa globosa. Tronco derecho que normalmente alcanza de 2 a 2,5 m. de altura, con corteza cubierta de lenticelas, lisa, adherida, de color ceniciento verdoso sobre los ramos y escamosa y gris parda sobre las partes viejas del ГғЖ’ГӮВЎrbol. Tiene una vida de unos 60-80 aГғЖ’ГӮВұos. Las ramas se insertan en ГғЖ’ГӮВЎngulo abierto sobre el tallo, de color verde oscuro, a veces tendiendo a negruzco o violГғЖ’ГӮВЎceo. Los brotes jГғЖ’ГӮВіvenes terminan con frecuencia en una espina',400,8.00,6.00),('FR-43','Membrillero Gigante de Wranja','Frutales','','Frutales Talavera S.A','',400,8.00,6.00),('FR-44','Melocotonero Spring Crest','Frutales','','Melocotones de Cieza S.A.','ГғЖ’ГӮВҒrbol caducifolio de porte bajo con corteza lisa, de color ceniciento. Sus hojas son alargadas con el margen ligeramente aserrado, de color verde brillante, algo mГғЖ’ГӮВЎs claras por el envГғЖ’ГӮВ©s. El melocotonero estГғЖ’ГӮВЎ muy arraigado en la cultura asiГғЖ’ГӮВЎtica.\r\nEn JapГғЖ’ГӮВіn, el noble heroe Momotaro, una especie de Cid japonГғЖ’ГӮВ©s, naciГғЖ’ГӮВі del interior de un enorme melocotГғЖ’ГӮВіn que flotaba rГғЖ’ГӮВӯo abajo.\r\nEn China se piensa que comer melocotГғЖ’ГӮВіn confiere longevidad al ser humano, ya que formaba parte de la dieta de sus dioses inmortales.',400,8.00,6.00),('FR-45','Melocotonero Amarillo de Agosto','Frutales','','Melocotones de Cieza S.A.','ГғЖ’ГӮВҒrbol caducifolio de porte bajo con corteza lisa, de color ceniciento. Sus hojas son alargadas con el margen ligeramente aserrado, de color verde brillante, algo mГғЖ’ГӮВЎs claras por el envГғЖ’ГӮВ©s. El melocotonero estГғЖ’ГӮВЎ muy arraigado en la cultura asiГғЖ’ГӮВЎtica.\r\nEn JapГғЖ’ГӮВіn, el noble heroe Momotaro, una especie de Cid japonГғЖ’ГӮВ©s, naciГғЖ’ГӮВі del interior de un enorme melocotГғЖ’ГӮВіn que flotaba rГғЖ’ГӮВӯo abajo.\r\nEn China se piensa que comer melocotГғЖ’ГӮВіn confiere longevidad al ser humano, ya que formaba parte de la dieta de sus dioses inmortales.',400,8.00,6.00),('FR-46','Melocotonero Federica','Frutales','','Melocotones de Cieza S.A.','ГғЖ’ГӮВҒrbol caducifolio de porte bajo con corteza lisa, de color ceniciento. Sus hojas son alargadas con el margen ligeramente aserrado, de color verde brillante, algo mГғЖ’ГӮВЎs claras por el envГғЖ’ГӮВ©s. El melocotonero estГғЖ’ГӮВЎ muy arraigado en la cultura asiГғЖ’ГӮВЎtica.\r\nEn JapГғЖ’ГӮВіn, el noble heroe Momotaro, una esp